const SAMAKY_LOGO_B64 = "data:image/png;base64,";
const AVATAR_B64 = "data:image/jpeg;base64,";
const QR_B64 = "data:image/png;base64,";

function SAMAKYLogo({ white = false, size = 32 }) {
  const height = size;
  // The logo image is ~1750x500 aspect ratio (wide), so width scales accordingly
  const width = Math.round(height * 3.5);
  if (white) {
    // For white version (on dark bg), use CSS filter to invert
    return (
      <img
        src={SAMAKY_LOGO_B64}
        alt="samaky"
        style={{
          height: height,
          width: "auto",
          maxWidth: width,
          objectFit: "contain",
          filter: "brightness(0) invert(1)",
          display: "block",
        }}
      />
    );
  }
  return (
    <img
      src={SAMAKY_LOGO_B64}
      alt="samaky"
      style={{
        height: height,
        width: "auto",
        maxWidth: width,
        objectFit: "contain",
        display: "block",
      }}
    />
  );
}

