function causeIcon(cause) {
  if (cause === "Environment") return <Icons.Leaf />;
  if (cause === "Animals")     return <Icons.Paw />;
  if (cause === "Education")   return <Icons.Book />;
  if (cause === "Health")      return <Icons.Heart />;
  return <Icons.Globe />;
}

function causeIconSvg(cause, size=16) {
  if (cause === "Environment") return <Icons.LeafIcon size={size} />;
  if (cause === "Animals")     return <Icons.PawIcon size={size} />;
  if (cause === "Education")   return <Icons.BookIcon size={size} />;
  if (cause === "Health")      return <Icons.HeartIcon size={size} />;
  return <Icons.Globe />;
}

function DonutChart({ data, size=120, stroke=22 }) {
  const r = (size - stroke) / 2;
  const circ = 2 * Math.PI * r;
  let offset = 0;
  const slices = data.map(d => {
    const dash = (d.pct / 100) * circ;
    const gap  = circ - dash;
    const s = { ...d, dash, gap, offset };
    offset += dash;
    return s;
  });
  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} style={{ transform:"rotate(-90deg)" }}>
      {slices.map((s,i) => (
        <circle key={i} cx={size/2} cy={size/2} r={r} fill="none" stroke={s.color} strokeWidth={stroke}
          strokeDasharray={`${s.dash} ${s.gap}`} strokeDashoffset={-s.offset} strokeLinecap="butt" />
      ))}
    </svg>
  );
}

